// SPDX-License-Identifier: MIT
pragma solidity ^0.8.19;

/**
 * @title Denomination Library for zkCross
 * @notice Manages fixed-denomination transfers for privacy preservation
 * @dev Transfer amounts are split into fixed denominations to prevent
 *      amount-based linkability attacks. All sub-transactions have the 
 *      same amount, increasing the anonymity set.
 * 
 * Reference: zkCross paper Section 5.1 - Denomination mechanism
 */
library Denomination {
    /// @notice Supported denominations in wei
    /// @dev Using powers of 10 for simplicity. In production, these would be
    ///      chosen based on expected transaction volume for each denomination tier.
    uint256 constant DENOM_1   = 0.001 ether;  // 1e15 wei
    uint256 constant DENOM_2   = 0.01 ether;   // 1e16 wei
    uint256 constant DENOM_3   = 0.1 ether;    // 1e17 wei
    uint256 constant DENOM_4   = 1 ether;      // 1e18 wei
    uint256 constant DENOM_5   = 10 ether;     // 1e19 wei
    uint256 constant DENOM_6   = 100 ether;    // 1e20 wei

    uint256 constant NUM_DENOMINATIONS = 6;

    /**
     * @notice Decompose an amount into fixed denominations
     * @param amount The total amount to decompose
     * @return denomCounts Array of counts for each denomination tier
     * @return remainder Amount that couldn't be decomposed (should be 0)
     */
    function decompose(uint256 amount) 
        internal pure returns (uint256[6] memory denomCounts, uint256 remainder) 
    {
        remainder = amount;

        // Greedy decomposition from largest to smallest
        denomCounts[5] = remainder / DENOM_6;
        remainder -= denomCounts[5] * DENOM_6;

        denomCounts[4] = remainder / DENOM_5;
        remainder -= denomCounts[4] * DENOM_5;

        denomCounts[3] = remainder / DENOM_4;
        remainder -= denomCounts[3] * DENOM_4;

        denomCounts[2] = remainder / DENOM_3;
        remainder -= denomCounts[2] * DENOM_3;

        denomCounts[1] = remainder / DENOM_2;
        remainder -= denomCounts[1] * DENOM_2;

        denomCounts[0] = remainder / DENOM_1;
        remainder -= denomCounts[0] * DENOM_1;
    }

    /**
     * @notice Check if an amount is a valid denomination
     * @param amount The amount to check
     * @return True if the amount is one of the supported denominations
     */
    function isValidDenomination(uint256 amount) internal pure returns (bool) {
        return (amount == DENOM_1 || amount == DENOM_2 || amount == DENOM_3 ||
                amount == DENOM_4 || amount == DENOM_5 || amount == DENOM_6);
    }

    /**
     * @notice Get denomination value by index
     */
    function getDenomination(uint256 index) internal pure returns (uint256) {
        if (index == 0) return DENOM_1;
        if (index == 1) return DENOM_2;
        if (index == 2) return DENOM_3;
        if (index == 3) return DENOM_4;
        if (index == 4) return DENOM_5;
        if (index == 5) return DENOM_6;
        revert("Invalid denomination index");
    }

    /**
     * @notice Compute the total number of sub-transfers needed for an amount
     * @dev Per paper Section 5.2.1 / Theorem 1: arbitrary amounts are split into
     *      multiple fixed-denomination transfers to ensure unlinkability.
     *      E.g. 6 ETH → 6 × 1 ETH transfers; 15.23 ETH → 1×10 + 5×1 + 2×0.1 + 3×0.01
     * @param amount The total amount to split
     * @return count Total number of sub-transfers (sum of decomposition counts)
     */
    function totalSubTransfers(uint256 amount) internal pure returns (uint256 count) {
        (uint256[6] memory denomCounts, ) = decompose(amount);
        for (uint256 i = 0; i < 6; i++) {
            count += denomCounts[i];
        }
    }

    /**
     * @notice Get the list of denomination values for an amount decomposition
     * @dev Returns an array of denomination amounts, one per sub-transfer.
     *      Caller must provide a sufficiently large maxCount.
     * @param amount The total amount to decompose
     * @param maxCount Maximum expected sub-transfers (to size the return array)
     * @return values Array of denomination values for each sub-transfer
     * @return actualCount Actual number of sub-transfers
     */
    function listSubTransfers(uint256 amount, uint256 maxCount)
        internal pure returns (uint256[] memory values, uint256 actualCount)
    {
        (uint256[6] memory denomCounts, ) = decompose(amount);
        values = new uint256[](maxCount);
        actualCount = 0;

        // Iterate from largest to smallest denomination
        for (uint256 tier = 6; tier > 0; tier--) {
            uint256 idx = tier - 1;
            uint256 denomValue = getDenomination(idx);
            for (uint256 j = 0; j < denomCounts[idx]; j++) {
                require(actualCount < maxCount, "Too many sub-transfers");
                values[actualCount] = denomValue;
                actualCount++;
            }
        }
    }
}

project/contracts/libraries/Groth16Verif.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.19;

/**
 * @title Groth16 Verifier Library for zkCross
 * @notice On-chain zk-SNARK (Groth16) proof verification using bn256 precompiled contracts
 * @dev Uses precompiles at addresses 0x06 (bn256Add), 0x07 (bn256ScalarMul), 0x08 (bn256Pairing)
 * 
 * The Groth16 verification equation:
 *   e(A, B) = e(alpha, beta) * e(sum(vk_i * x_i), gamma) * e(C, delta)
 * 
 * Rearranged for single pairing check:
 *   e(-A, B) * e(alpha, beta) * e(vk_x, gamma) * e(C, delta) = 1
 * 
 * Reference: zkCross paper Section 6 - Implementation Details
 *            Gas cost: ~440,000 gas for verification
 */
library Groth16Verifier {

    // ==========================================
    // Data Structures
    // ==========================================

    /// @notice Point on G1 (bn256 curve)
    struct G1Point {
        uint256 x;
        uint256 y;
    }

    /// @notice Point on G2 (bn256 twist curve) 
    struct G2Point {
        uint256[2] x; // x coordinate (Fp2 element: x[0] + x[1]*u)
        uint256[2] y; // y coordinate (Fp2 element: y[0] + y[1]*u)
    }

    /// @notice Groth16 proof consisting of three group elements
    struct Proof {
        G1Point a;      // Proof element A (G1)
        G2Point b;      // Proof element B (G2)
        G1Point c;      // Proof element C (G1)
    }

    /// @notice Verification key for a specific circuit
    struct VerifyingKey {
        G1Point alpha;      // alpha * G1
        G2Point beta;       // beta * G2
        G2Point gamma;      // gamma * G2
        G2Point delta;      // delta * G2
        G1Point[] ic;       // IC[i] for public inputs (length = numInputs + 1)
    }

    // ==========================================
    // bn256 Curve Constants
    // ==========================================

    /// @dev Field modulus for bn256
    uint256 internal constant FIELD_MODULUS = 
        21888242871839275222246405745257275088696311157297823662689037894645226208583;

    /// @dev Scalar field order for bn256
    uint256 internal constant SCALAR_MODULUS = 
        21888242871839275222246405745257275088548364400416034343698204186575808495617;

    // ==========================================
    // Elliptic Curve Operations via Precompiles
    // ==========================================

    /// @notice Negate a G1 point (reflect over x-axis)
    /// @dev -P = (x, FIELD_MODULUS - y)
    function negate(G1Point memory p) internal pure returns (G1Point memory) {
        if (p.x == 0 && p.y == 0) {
            return G1Point(0, 0); // Point at infinity
        }
        return G1Point(p.x, FIELD_MODULUS - (p.y % FIELD_MODULUS));
    }

    /// @notice Add two G1 points using precompile at 0x06
    /// @dev Gas cost: 150 (Istanbul)
    function addition(G1Point memory p1, G1Point memory p2) 
        internal view returns (G1Point memory r) 
    {
        uint256[4] memory input;
        input[0] = p1.x;
        input[1] = p1.y;
        input[2] = p2.x;
        input[3] = p2.y;

        bool success;
        assembly {
            success := staticcall(sub(gas(), 2000), 0x06, input, 0x80, r, 0x40)
        }
        require(success, "bn256Add failed");
    }

    /// @notice Scalar multiplication on G1 using precompile at 0x07
    /// @dev Gas cost: 6,000 (Istanbul)
    function scalarMul(G1Point memory p, uint256 s) 
        internal view returns (G1Point memory r) 
    {
        uint256[3] memory input;
        input[0] = p.x;
        input[1] = p.y;
        input[2] = s;

        bool success;
        assembly {
            success := staticcall(sub(gas(), 2000), 0x07, input, 0x60, r, 0x40)
        }
        require(success, "bn256ScalarMul failed");
    }

    /// @notice Pairing check using precompile at 0x08
    /// @dev Checks: e(p1[0], p2[0]) * e(p1[1], p2[1]) * ... = 1
    /// @dev Gas cost: 45,000 + 34,000 * numPairs (Istanbul)
    function pairing(G1Point[] memory p1, G2Point[] memory p2) 
        internal view returns (bool) 
    {
        require(p1.length == p2.length, "Pairing length mismatch");

        uint256 inputSize = p1.length * 6; // 6 uint256 per pair
        uint256[] memory input = new uint256[](inputSize);

        for (uint256 i = 0; i < p1.length; i++) {
            uint256 j = i * 6;
            input[j + 0] = p1[i].x;
            input[j + 1] = p1[i].y;
            input[j + 2] = p2[i].x[1]; // Note: Fp2 encoding order
            input[j + 3] = p2[i].x[0];
            input[j + 4] = p2[i].y[1];
            input[j + 5] = p2[i].y[0];
        }

        uint256[1] memory result;
        bool success;

        assembly {
            success := staticcall(
                sub(gas(), 2000),
                0x08,
                add(input, 0x20),
                mul(inputSize, 0x20),
                result,
                0x20
            )
        }
        require(success, "bn256Pairing failed");
        return result[0] == 1;
    }

    // ==========================================
    // Groth16 Verification
    // ==========================================

    /**
     * @notice Verify a Groth16 proof against a verification key and public inputs
     * @param vk The verification key for the circuit
     * @param proof The Groth16 proof (A, B, C)
     * @param publicInputs Array of public input values
     * @return True if the proof is valid
     * 
     * @dev Verification equation:
     *   e(-A, B) * e(alpha, beta) * e(vk_x, gamma) * e(C, delta) = 1
     * 
     * Where vk_x = IC[0] + sum(IC[i+1] * publicInputs[i])
     */
    function verify(
        VerifyingKey memory vk,
        Proof memory proof,
        uint256[] memory publicInputs
    ) internal view returns (bool) {
        require(publicInputs.length + 1 == vk.ic.length, "Invalid public inputs length");

        // Validate public inputs are in the scalar field
        for (uint256 i = 0; i < publicInputs.length; i++) {
            require(publicInputs[i] < SCALAR_MODULUS, "Public input exceeds field");
        }

        // Compute vk_x = IC[0] + sum(IC[i+1] * publicInputs[i])
        G1Point memory vk_x = vk.ic[0];
        for (uint256 i = 0; i < publicInputs.length; i++) {
            vk_x = addition(vk_x, scalarMul(vk.ic[i + 1], publicInputs[i]));
        }

        // Prepare pairing check: e(-A, B) * e(alpha, beta) * e(vk_x, gamma) * e(C, delta) = 1
        G1Point[] memory g1Points = new G1Point[](4);
        G2Point[] memory g2Points = new G2Point[](4);

        g1Points[0] = negate(proof.a);  // -A
        g2Points[0] = proof.b;          // B

        g1Points[1] = vk.alpha;         // alpha
        g2Points[1] = vk.beta;          // beta

        g1Points[2] = vk_x;             // vk_x (computed)
        g2Points[2] = vk.gamma;         // gamma

        g1Points[3] = proof.c;          // C
        g2Points[3] = vk.delta;         // delta

        return pairing(g1Points, g2Points);
    }
}

